script:
frappe.ui.form.on('customer_grc', {
	refresh: function(frm) {
		if (frm.is_new()) return;
		render_grc_stats_dashboard(frm);
	}
});

function render_grc_stats_dashboard(frm) {
	frappe.call({
		method: 'grc_module.api.get_company_stats',
		args: { company: frm.doc.name },
		callback: function(r) {
			if (r.exc || !r.message) return;
			const d = r.message;
			const score = parseFloat(d.compliance_score) || 0;
			const score_color = score >= 80 ? '#2ecc71' : score >= 60 ? '#f39c12' : '#e74c3c';
			const score_cls = score >= 80 ? 'success' : score >= 60 ? 'warning' : 'danger';
			const ctrl_pct = d.controls.total > 0 ? Math.round(d.controls.conforme / d.controls.total * 100) : 0;

			const html = `
<style>
.grc-db{padding:8px 0 4px}
.grc-db-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(150px,1fr));gap:10px;margin-bottom:4px}
.grc-card{background:var(--card-bg,#fff);border:1px solid var(--border-color,#e2e8f0);border-radius:8px;padding:14px 16px;text-align:center;position:relative;overflow:hidden}
.grc-card::before{content:'';position:absolute;top:0;left:0;right:0;height:3px}
.grc-card.c-danger::before{background:#e74c3c}.grc-card.c-warning::before{background:#f39c12}
.grc-card.c-success::before{background:#2ecc71}.grc-card.c-purple::before{background:#9b59b6}
.grc-card.c-blue::before{background:#3498db}.grc-card.c-teal::before{background:#1abc9c}
.grc-num{font-size:26px;font-weight:700;color:var(--text-color,#1a202c);line-height:1.1}
.grc-lbl{font-size:10px;color:var(--text-muted,#718096);margin-top:3px;text-transform:uppercase;letter-spacing:.6px}
.grc-sub{font-size:11px;color:var(--text-muted,#718096);margin-top:6px;line-height:1.4}
.grc-sub b{font-weight:600}
.grc-bar-wrap{background:#e2e8f0;border-radius:99px;height:5px;margin-top:8px;overflow:hidden}
.grc-bar{height:100%;border-radius:99px;transition:width .8s ease}
</style>
<div class="grc-db">
  <div class="grc-db-grid">

    <div class="grc-card c-${score_cls}">
      <div class="grc-num">${score}<small style="font-size:13px">%</small></div>
      <div class="grc-lbl">${__('Conformité')}</div>
      <div class="grc-bar-wrap"><div class="grc-bar" style="width:${Math.min(score,100)}%;background:${score_color}"></div></div>
    </div>

    <div class="grc-card c-${d.violations.critical > 0 ? 'danger' : d.violations.open > 0 ? 'warning' : 'success'}">
      <div class="grc-num">${d.violations.total}</div>
      <div class="grc-lbl">${__('Violations')}</div>
      <div class="grc-sub">
        <b style="color:#e74c3c">${d.violations.critical}</b> critiques<br>
        <b style="color:#f39c12">${d.violations.open}</b> ouvertes
      </div>
    </div>

    <div class="grc-card c-${d.action_plans.overdue > 0 ? 'danger' : d.action_plans.open > 0 ? 'warning' : 'success'}">
      <div class="grc-num">${d.action_plans.total}</div>
      <div class="grc-lbl">${__('Plans d\'action')}</div>
      <div class="grc-sub">
        <b style="color:#f39c12">${d.action_plans.open}</b> en cours<br>
        <b style="color:#e74c3c">${d.action_plans.overdue}</b> en retard
      </div>
    </div>

    <div class="grc-card c-purple">
      <div class="grc-num">${d.make_rights.total}</div>
      <div class="grc-lbl">${__('Demandes droits')}</div>
      <div class="grc-sub"><b style="color:#9b59b6">${d.make_rights.pending}</b> en attente</div>
    </div>

    <div class="grc-card c-${ctrl_pct >= 70 ? 'success' : ctrl_pct >= 40 ? 'warning' : 'danger'}">
      <div class="grc-num">${d.controls.total}</div>
      <div class="grc-lbl">${__('Contrôles')}</div>
      <div class="grc-sub">
        <b style="color:#2ecc71">${d.controls.conforme}</b> conformes<br>
        <b style="color:#e74c3c">${d.controls.non_conforme}</b> non conformes
      </div>
    </div>

    <div class="grc-card c-teal">
      <div class="grc-num">${d.documents.total}</div>
      <div class="grc-lbl">${__('Documents')}</div>
      <div class="grc-sub"><b>${d.traitements.total}</b> traitements</div>
    </div>

  </div>
</div>`;

			frm.dashboard.add_section(html, __('Tableau de bord GRC'));
		}
	});
}
